parameters.query:
WITH alvo_deal AS (
  SELECT id, person_id FROM commercial_deals WHERE kommo_lead_id = '22932422'
),
alvo_conv AS (
  SELECT id FROM commercial_conversations
  WHERE commercial_deal_id IN (SELECT id FROM alvo_deal)
),
del_msg AS (
  DELETE FROM commercial_conversation_messages
  WHERE commercial_conversation_id IN (SELECT id FROM alvo_conv) RETURNING 1
),
del_conv AS (
  DELETE FROM commercial_conversations
  WHERE id IN (SELECT id FROM alvo_conv) RETURNING 1
),
del_deal AS (
  DELETE FROM commercial_deals
  WHERE id IN (SELECT id FROM alvo_deal) RETURNING person_id
)
DELETE FROM persons WHERE id IN (SELECT person_id FROM del_deal);

UPDATE commercial_conversations
SET kommo_external_conversation_id = NULL
WHERE kommo_external_conversation_id = 'undefined';
